#ifndef GEMM_N2048_K4096_KERNEL_H_
#define GEMM_N2048_K4096_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_fp16.h>

#include <cstdint>
#include <cstdio>

#ifndef CUDA_CHECK
#define CUDA_CHECK(call)                                                                 \
  do {                                                                                   \
    cudaError_t _e = (call);                                                             \
    if (_e != cudaSuccess) {                                                             \
      std::printf("CUDA error %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(_e)); \
    }                                                                                    \
  } while (0)
#endif

// Computes C[M,N] = A[M,K] * B[N,K]^T, with N=2048, K=4096.
// A, B, C are fp16. Accumulation is fp32.
// A is row-major [M,K]. B is row-major [N,K]. Output C is row-major [M,N].
void gemm_n2048_k4096_launcher(const half* A, const half* B, half* C, int M, cudaStream_t stream);

#endif  // GEMM_N2048_K4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <mma.h>

using nvcuda::wmma::fragment;
using nvcuda::wmma::matrix_a;
using nvcuda::wmma::matrix_b;
using nvcuda::wmma::accumulator;
using nvcuda::wmma::row_major;
using nvcuda::wmma::col_major;

static constexpr int N_CONST = 2048;
static constexpr int K_CONST = 4096;

static constexpr int WMMA_M = 16;
static constexpr int WMMA_N = 16;
static constexpr int WMMA_K = 16;

// 8 warps/block (256 threads): tile 64x32 (WARPS_M x WARPS_N) wmma tiles.
static constexpr int WARPS_M = 4;
static constexpr int WARPS_N = 2;
static constexpr int WARPS_PER_BLOCK = WARPS_M * WARPS_N;  // 8
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;

static constexpr int BLOCK_M = WARPS_M * WMMA_M;  // 64
static constexpr int BLOCK_N = WARPS_N * WMMA_N;  // 32

// Store accumulator fragment to global C with M-guard. N is constant and grid covers it exactly.
__device__ __forceinline__ void store_accum_tile_guarded(
    half* __restrict__ C, int ldc,
    int m0, int n0,
    const fragment<accumulator, WMMA_M, WMMA_N, WMMA_K, float>& acc,
    int M,
    float* __restrict__ warp_smem // points to per-warp 16x16 float tile
) {
  nvcuda::wmma::store_matrix_sync(warp_smem, acc, WMMA_N, nvcuda::wmma::mem_row_major);
  __syncwarp();

  const int tid = int(threadIdx.x);
  const int lane = tid & 31;

#pragma unroll
  for (int idx = lane; idx < WMMA_M * WMMA_N; idx += 32) {
    const int i = idx / WMMA_N;
    const int j = idx % WMMA_N;
    const int row = m0 + i;
    const int col = n0 + j;
    if (row < M) {
      // col always in-range (0..2047) by construction
      C[row * ldc + col] = __float2half_rn(warp_smem[idx]);
    }
  }
}

extern "C" __global__ void gemm_n2048_k4096_wmma_kernel(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M) {
#if __CUDA_ARCH__ >= 800
  // Block tile origin
  const int block_m0 = int(blockIdx.y) * BLOCK_M;
  const int block_n0 = int(blockIdx.x) * BLOCK_N;

  const int tid = int(threadIdx.x);
  const int warp_id = tid >> 5;  // 0..7
  if (warp_id >= WARPS_PER_BLOCK) return;

  const int warp_m = warp_id / WARPS_N;  // 0..3
  const int warp_n = warp_id % WARPS_N;  // 0..1

  const int m0 = block_m0 + warp_m * WMMA_M;
  const int n0 = block_n0 + warp_n * WMMA_N;
  if (n0 >= N_CONST) return;

  constexpr int lda = K_CONST;
  constexpr int ldb = K_CONST;     // B is [N,K] row-major
  constexpr int ldc = N_CONST;

  fragment<accumulator, WMMA_M, WMMA_N, WMMA_K, float> acc;
  nvcuda::wmma::fill_fragment(acc, 0.0f);

  fragment<matrix_a, WMMA_M, WMMA_N, WMMA_K, half, row_major> a_frag;
  // We want C = A * (B^T). That is dot over K with B[n, k].
  // Treat B as a "col_major" matrix of shape K x N with leading dimension ldb (=K),
  // so that element (k, n) maps to B[n*ldb + k] which matches row-major [N,K].
  fragment<matrix_b, WMMA_M, WMMA_N, WMMA_K, half, col_major> b_frag;

  // Shared memory:
  // 1) per-warp float tile for storing accumulators (8 warps * 256 floats).
  extern __shared__ __align__(16) unsigned char smem_raw[];
  float* smem_f32 = reinterpret_cast<float*>(smem_raw);
  float* warp_smem = smem_f32 + warp_id * (WMMA_M * WMMA_N);

  // 2) tail A tile staging for partial M (only needed when m0+16 > M).
  // Use a dedicated shared region after f32 store area.
  half* As_tail = reinterpret_cast<half*>(smem_f32 + WARPS_PER_BLOCK * (WMMA_M * WMMA_N));
  // Layout: As_tail[warp_id][256]
  As_tail += warp_id * (WMMA_M * WMMA_K);

  const bool full_m = (m0 + WMMA_M) <= M;

#pragma unroll
  for (int k0 = 0; k0 < K_CONST; k0 += WMMA_K) {
    const half* tileB = B + n0 * ldb + k0;

    if (full_m) {
      const half* tileA = A + m0 * lda + k0;
      nvcuda::wmma::load_matrix_sync(a_frag, tileA, lda);
    } else {
      // Load a 16x16 A tile with row guard into per-warp shared, then load from shared.
      // Only threads within this warp participate.
      const int lane = tid & 31;
#pragma unroll
      for (int idx = lane; idx < (WMMA_M * WMMA_K); idx += 32) {
        const int i = idx / WMMA_K;
        const int j = idx % WMMA_K;
        const int row = m0 + i;
        half v = __float2half(0.0f);
        if (row < M) v = A[row * lda + (k0 + j)];
        As_tail[idx] = v;
      }
      __syncwarp();
      nvcuda::wmma::load_matrix_sync(a_frag, As_tail, WMMA_K);
      __syncwarp();
    }

    nvcuda::wmma::load_matrix_sync(b_frag, tileB, ldb);
    nvcuda::wmma::mma_sync(acc, a_frag, b_frag, acc);
  }

  store_accum_tile_guarded(C, ldc, m0, n0, acc, M, warp_smem);
#else
  (void)A; (void)B; (void)C; (void)M;
#endif
}

void gemm_n2048_k4096_launcher(const half* A, const half* B, half* C, int M, cudaStream_t stream) {
  dim3 block(THREADS_PER_BLOCK, 1, 1);
  dim3 grid((N_CONST + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M, 1);

  // Shared memory:
  // - per-warp accumulator store: WARPS_PER_BLOCK * 256 floats
  // - per-warp tail A tile: WARPS_PER_BLOCK * 256 half
  const size_t smem_store_bytes =
      size_t(WARPS_PER_BLOCK) * size_t(WMMA_M * WMMA_N) * sizeof(float);
  const size_t smem_tailA_bytes =
      size_t(WARPS_PER_BLOCK) * size_t(WMMA_M * WMMA_K) * sizeof(half);
  const size_t smem_bytes = smem_store_bytes + smem_tailA_bytes;

  gemm_n2048_k4096_wmma_kernel<<<grid, block, smem_bytes, stream>>>(A, B, C, M);
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cstdint>
#include <sstream>
#include <stdexcept>

#include "kernel.h"

static void check_tensor_cuda_fp16_contig_2d(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::runtime_error(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::runtime_error(oss.str());
  }
  if (t.dtype() != torch::kFloat16) {
    std::ostringstream oss; oss << name << " must be torch.float16";
    throw std::runtime_error(oss.str());
  }
  if (t.dim() != 2) {
    std::ostringstream oss; oss << name << " must be rank-2";
    throw std::runtime_error(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::runtime_error(oss.str());
  }
}

torch::Tensor run(torch::Tensor A, torch::Tensor B) {
  check_tensor_cuda_fp16_contig_2d(A, "A");
  check_tensor_cuda_fp16_contig_2d(B, "B");

  const int64_t M64  = A.size(0);
  const int64_t K64  = A.size(1);
  const int64_t N64  = B.size(0);
  const int64_t Kb64 = B.size(1);

  if (K64 != 4096) throw std::runtime_error("A.size(1) (K) must be 4096");
  if (N64 != 2048) throw std::runtime_error("B.size(0) (N) must be 2048");
  if (Kb64 != 4096) throw std::runtime_error("B.size(1) (K) must be 4096");
  if (M64 < 0 || M64 > INT32_MAX) throw std::runtime_error("M out of supported range");

  auto C = torch::empty({M64, N64}, torch::TensorOptions().device(A.device()).dtype(torch::kFloat16));

  // Use PyTorch current stream (important for correctness with surrounding ops).
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(A.device().index());

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  gemm_n2048_k4096_launcher(A_ptr, B_ptr, C_ptr, static_cast<int>(M64), stream);

  // Surface async errors from launch.
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return C;
}

// kwargs-friendly wrapper
torch::Tensor run_kwargs(const torch::Tensor& A, const torch::Tensor& B) {
  return run(A, B);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n2048_k4096: C = A @ B.T (fp16 WMMA, N=2048, K=4096)");
  m.def("run_kwargs", &run_kwargs, "gemm_n2048_k4096 kwargs helper");
}
